### 1. CSRF 공격 방지

CSRF(Cross-Site Request Forgery) 공격은 사용자가 자신의 의지와는 무관하게 공격자가 의도한 동작을 수행하도록 하는 공격입니다. 이를 방지하기 위해 다음과 같은 스크립트를 작성할 수 있습니다.

```javascript
// CSRF 토큰 생성
const csrfToken = document.createElement('input');
csrfToken.name = 'csrf_token';
csrfToken.value = Math.random().toString(36).substr(2);
document.head.appendChild(csrfToken);

// CSRF 토큰 검증
function validateCsrfToken() {
  const csrfTokenInput = document.querySelector('input[name="csrf_token"]');
  if (!csrfTokenInput) {
    return false;
  }
  const csrfTokenValue = csrfTokenInput.value;
  const storedCsrfToken = localStorage.getItem('csrf_token');
  if (csrfTokenValue!== storedCsrfToken) {
    return false;
  }
  localStorage.setItem('csrf_token', csrfTokenValue);
  return true;
}

// CSRF 토큰 생성 및 검증
function csrfProtection() {
  const csrfToken = Math.random().toString(36).substr(2);
  document.head.appendChild(csrfToken);
  localStorage.setItem('csrf_token', csrfToken);
  return validateCsrfToken();
}
```

